<div class="page-header"><div><h2>API Analytics</h2><p>Recent API request volume, error rate, and token-backed usage visibility.</p></div></div>
<div class="grid grid-3"><div class="card"><div class="stat-label">Total Requests</div><div class="stat-value"><?= e((string)($summary['total_requests'] ?? 0)) ?></div></div><div class="card"><div class="stat-label">Errors</div><div class="stat-value"><?= e((string)($summary['error_requests'] ?? 0)) ?></div></div><div class="card"><div class="stat-label">Last Request</div><div class="stat-value"><?= e((string)($summary['last_request_at'] ?? 'N/A')) ?></div></div></div>
